# fix_orders_store_supabase.ps1
Write-Host "Conectando Pedidos a Supabase..." -ForegroundColor Cyan
$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$text = [System.Text.Encoding]::UTF8.GetString($bytes)
[System.IO.File]::WriteAllText((Resolve-Path ".").Path + "\src\modules\ventas\store\orders.store.ts", $text, [System.Text.Encoding]::UTF8)
Write-Host "Listo! Pedidos conectado a Supabase" -ForegroundColor Green
